        	this.dsSearch.addRow();
        	this.dsSearch.setColumn(0, "aplyNo", this.divForm.form.divSch.form.edtAplyNo.value);
        	this.dsSearch.setColumn(0, "bgngYmd", this.divForm.form.divSch.form.divCal.form.calBgngYmd.value);
        	this.dsSearch.setColumn(0, "endYmd", this.divForm.form.divSch.form.divCal.form.calEndYmd.value);
        	this.dsSearch.setColumn(0, "custType", this.divForm.form.divSch.form.cboCustType.value);
        	this.dsSearch.setColumn(0, "aplyKnd", this.divForm.form.divSch.form.cboAplyKnd.value);
        	this.dsSearch.setColumn(0, "srvcAplySe", this.divForm.form.divSch.form.cboSrvcAplySe.value);
        	this.dsSearch.setColumn(0, "endCd", "TSPCLO010"); // TSPCLO010 : 정상종료

        	var strSvcId    = "selectAddedFcltyHstryList";
        	var strSvcUrl   = "addedFclty/selectAddedFcltyHstryList.do";
        	var inData      = "dsSearch=dsSearch";
